379	    <div className="relative flex items-center">
380	      <select
381	        aria-label={label}
382	        title={label}
383	        value={value}
384	        onChange={(e) => onChange(e.target.value)}
385	        className="h-7 cursor-pointer appearance-none rounded-md border border-border bg-surface pl-2.5 pr-6 text-xs font-medium text-foreground shadow-sm transition-colors hover:bg-surface-strong focus:outline-none focus:ring-1 focus:ring-accent"
386	      >
387	        {options.map((o) => (
388	          <option key={o.id} value={o.id}>
389	            {o.label}
390	          </option>
391	        ))}
392	      </select>
393	      <Icons.disclosureOpen
394	        size={11}
395	        className="pointer-events-none absolute right-1.5 text-muted"
