402	interface IconButtonProps {
403	  Icon: LucideLikeIcon;
404	  label: string;
405	  onClick?: (e: MouseEvent<HTMLButtonElement>) => void;
406	  badge?: number;
407	  ['data-testid']?: string;
408	  ['data-current-theme']?: string;
409	}
410	
411	function IconButton({
412	  Icon,
413	  label,
414	  onClick,
415	  badge,
416	  'data-testid': testId,
417	  'data-current-theme': currentTheme,
418	}: IconButtonProps): JSX.Element {
419	  const handleFocus = useCallback((_e: FocusEvent<HTMLButtonElement>) => {
420	    /* no-op — declared so consumers can extend later. */
421	  }, []);
422	
423	  return (
424	    <button
425	      type="button"
426	      onClick={onClick}
427	      onFocus={handleFocus}
428	      aria-label={label}
429	      title={label}
430	      data-testid={testId}
431	      data-current-theme={currentTheme}
432	      className="relative inline-flex h-8 w-8 items-center justify-center rounded-md text-muted transition-colors hover:bg-surface hover:text-foreground"
433	    >
434	      <Icon size={ICON_SIZE.topbar} aria-hidden="true" />
435	      {typeof badge === 'number' && badge > 0 ? (
436	        <span
437	          data-testid="topbar-badge"
438	          aria-hidden="true"
439	          className="absolute -right-0.5 -top-0.5 inline-flex h-4 min-w-4 items-center justify-center rounded-pill bg-accent px-1 text-xs text-accent-foreground"
440	        >
441	          {badge}
442	        </span>
443	      ) : null}
444	    </button>
