1	/* BIM AI design tokens — default (light) chrome.
2	 *
3	 * Source of truth: spec/ui-ux-redesign-v1-spec.md §9 (chrome subset).
4	 * Drafting / category / line-weight tokens live in tokens-drafting.css.
5	 * Dark overrides live in tokens-dark.css.
6	 *
7	 * Naming rule: every token is semantic (no color literals in token names).
8	 */
9	
10	:root,
11	:root[data-theme='light'] {
12	  /* §9.1 Color — semantic chrome */
13	  --color-background: hsl(0 0% 100%);
14	  --color-foreground: hsl(220 18% 14%);
15	  --color-surface: hsl(220 16% 98%);
16	  --color-surface-strong: hsl(220 16% 95%);
17	  --color-surface-muted: hsl(220 16% 96%);
18	  --color-border: hsl(220 13% 90%);
19	  --color-border-strong: hsl(220 13% 80%);
20	  --color-muted-foreground: hsl(220 10% 44%);
21	  --color-accent: hsl(214 88% 50%);
22	  --color-accent-foreground: hsl(0 0% 100%);
23	  --color-accent-soft: color-mix(in srgb, hsl(214 88% 50%) 12%, hsl(0 0% 100%));
24	  --color-success: hsl(150 56% 38%);
25	  --color-warning: hsl(38 92% 50%);
26	  --color-danger: hsl(0 72% 50%);
27	  --color-info: hsl(213 86% 56%);
28	  --color-ring: color-mix(in srgb, hsl(214 88% 50%) 38%, transparent);
29	
30	  /* §9.4 Spacing (4 px base) */
31	  --space-0: 0;
32	  --space-1: 2px;
33	  --space-2: 4px;
34	  --space-3: 6px;
35	  --space-4: 8px;
36	  --space-5: 12px;
37	  --space-6: 16px;
38	  --space-7: 20px;
39	  --space-8: 24px;
40	  --space-10: 32px;
41	  --space-12: 40px;
42	
43	  /* §9.5 Radius */
44	  --radius-xs: 3px;
45	  --radius-sm: 4px;
46	  --radius-md: 6px;
47	  --radius-lg: 10px;
48	  --radius-xl: 14px;
49	  --radius-pill: 999px;
50	
51	  /* §9.6 Typography */
52	  --font-sans:
53	    'Inter', ui-sans-serif, system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto,
54	    Helvetica, Arial, 'Apple Color Emoji', 'Segoe UI Emoji';
55	  --font-mono:
56	    'JetBrains Mono', ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, 'Liberation Mono',
57	    'Courier New', monospace;
58	
59	  --text-xs: 11px;
60	  --text-xs-line: 16px;
61	  --text-sm: 12.5px;
62	  --text-sm-line: 18px;
63	  --text-base: 14px;
64	  --text-base-line: 20px;
65	  --text-md: 15px;
66	  --text-md-line: 22px;
67	  --text-lg: 17px;
68	  --text-lg-line: 24px;
69	  --text-xl: 20px;
70	  --text-xl-line: 28px;
71	  --text-mono-xs: 11px;
72	  --text-mono-xs-line: 16px;
73	  --text-mono-sm: 12px;
74	  --text-mono-sm-line: 18px;
75	  --text-eyebrow-tracking: 0.04em;
76	
77	  /* §9.7 Elevation */
78	  --elev-0: none;
79	  --elev-1: 0 1px 2px hsl(220 18% 14% / 0.04), 0 1px 1px hsl(220 18% 14% / 0.04);
80	  --elev-2: 0 4px 8px hsl(220 18% 14% / 0.06), 0 2px 4px hsl(220 18% 14% / 0.04);
81	  --elev-3: 0 12px 24px hsl(220 18% 14% / 0.08), 0 4px 8px hsl(220 18% 14% / 0.06);
82	
83	  /* §9.8 Motion */
84	  --motion-fast: 80ms;
